import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../Context/AuthContext';
import { useCart } from '../Context/CartContext';
import './CheckoutPage.css';

const CheckoutPage = () => {
    const { user, login } = useAuth();
    const { cart, total, clearCart } = useCart();
    const navigate = useNavigate();

    const [email, setEmail] = useState('');
    const [formData, setFormData] = useState({
        name: '',
        address: '',
        city: '',
        zip: ''
    });

    if (cart.length === 0) {
        navigate('/cart');
        return null;
    }

    const handleLogin = (e) => {
        e.preventDefault();
        if (email) login(email);
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        // TODO: Aquí iría la integración con pasarela de pagos
        clearCart();
        navigate('/confirmation');
    };

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    if (!user) {
        return (
            <div className="login-container">
                <h2 className="login-title">Inicia sesión para continuar</h2>
                <div className="login-card">
                    <form onSubmit={handleLogin} className="login-form">
                        <input
                            type="email"
                            placeholder="Tu correo electrónico"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="login-input"
                        />
                        <button type="submit" className="btn-primary">
                            Continuar como Invitado
                        </button>
                    </form>
                    <p className="login-note">
                        (Simulación: ingresa cualquier correo)
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="checkout-container">
            <h1 className="checkout-title">Checkout</h1>

            <div className="checkout-layout">
                <div>
                    <div className="checkout-section">
                        <h3 className="section-title">1. Datos de Envío</h3>
                        <form id="checkout-form" onSubmit={handleSubmit} className="checkout-form">
                            <div>
                                <label className="form-label">Nombre Completo</label>
                                <input
                                    type="text"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    required
                                    className="form-input"
                                />
                            </div>
                            <div>
                                <label className="form-label">Dirección</label>
                                <input
                                    type="text"
                                    name="address"
                                    value={formData.address}
                                    onChange={handleChange}
                                    required
                                    className="form-input"
                                />
                            </div>
                            <div className="form-row">
                                <div>
                                    <label className="form-label">Ciudad</label>
                                    <input
                                        type="text"
                                        name="city"
                                        value={formData.city}
                                        onChange={handleChange}
                                        required
                                        className="form-input"
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Código Postal</label>
                                    <input
                                        type="text"
                                        name="zip"
                                        value={formData.zip}
                                        onChange={handleChange}
                                        required
                                        className="form-input"
                                    />
                                </div>
                            </div>
                        </form>
                    </div>

                    <div className="checkout-section">
                        <h3 className="section-title">2. Pago</h3>
                        <div className="payment-placeholder">
                            Simulación de pago (No se requiere tarjeta real)
                        </div>
                    </div>
                </div>

                <div>
                    <div className="checkout-summary">
                        <h3 className="summary-title">Resumen</h3>
                        {cart.map(item => (
                            <div key={item.id} className="summary-item">
                                <span>{item.quantity}x {item.name}</span>
                                <span>${(item.price * item.quantity).toFixed(2)}</span>
                            </div>
                        ))}
                        <div className="summary-total">
                            <span>Total</span>
                            <span className="total-amount">${total.toFixed(2)}</span>
                        </div>

                        <button form="checkout-form" type="submit" className="btn-primary confirm-btn">
                            Confirmar Compra
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default CheckoutPage;
